#[test]
fn parses_signature_mutation_workflow_operator_schema() {
    let workflow: Workflow = serde_yaml::from_str(
        r#"
            version: 1
            inputs:
              - id: source
                path: ./unsigned.pdf
            tasks:
              - id: add_sig
                op:
                  pdf_sign:
                    add:
                      field_name: Approval
                      certificate: ./cert.pem
                      private_key: ./key.pem
                      contents_reserved_bytes: 8192
                inputs: [source]
              - id: delete_sig
                op:
                  pdf_sign:
                    delete_field:
                      field_name: Approval
                      destructive: true
                inputs: [add_sig]
              - id: timestamp
                op:
                  pdf_sign:
                    timestamp:
                      token: ./timestamp.tsr
                inputs: [delete_sig]
            outputs:
              - id: final
                from: timestamp
                path: ./report.json
            "#,
    )
    .unwrap();

    assert!(matches!(
        workflow.tasks[0].op,
        OperatorSpec::PdfSign(PdfSignOptions::Add(SignatureAddOptions { .. }))
    ));
    assert!(matches!(
        workflow.tasks[1].op,
        OperatorSpec::PdfSign(PdfSignOptions::DeleteField(SignatureDeleteFieldOptions {
            destructive: true,
            ..
        }))
    ));
    assert!(matches!(
        workflow.tasks[2].op,
        OperatorSpec::PdfSign(PdfSignOptions::Timestamp(TimestampAddOptions {
            token: Some(_),
            tsa_url: None,
        }))
    ));
}

